/* ─── Question generation helpers ───────────────────────────────────────── */

/** Fisher-Yates shuffle (non-mutating). */
function shuffleArr(arr: any[]) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

/** Pick `n` unique distractors from `pool`, excluding `correct`. */
function pickDistractors(correct: any, pool: any[], n = 3) {
  const others = pool.filter((v) => v !== correct);
  return shuffleArr(others).slice(0, n);
}

/** Place correct answer randomly among distractors and return { options, answer }. */
function buildOptions(correct: any, distractors: any[]) {
  const idx = Math.floor(Math.random() * (distractors.length + 1));
  const options = [...distractors];
  options.splice(idx, 0, correct);
  return { options, answer: idx };
}

/* — Generators — */

function buildCapitalQs(data: any[]) {
  const allCaps = data.map((c) => c.cap);
  return data.map((c) => {
    const distractors = pickDistractors(c.cap, allCaps);
    const { options, answer } = buildOptions(c.cap, distractors);
    return {
      q: `Quelle est la capitale ${c.prep} ?`,
      qHt: `Ki kapital ${c.ht} ?`,
      options,
      answer,
    };
  });
}

function buildCurrencyQs(data: any[]) {
  // Use unique currency names so distractors are always distinct from the correct answer.
  const uniqueCurs = [...new Set(data.map((c) => c.cur))];
  return data.map((c) => {
    const distractors = pickDistractors(c.cur, uniqueCurs);
    const { options, answer } = buildOptions(c.cur, distractors);
    return {
      q: `Quelle est la monnaie ${c.prep} ?`,
      qHt: `Ki lajan ${c.ht} ?`,
      options,
      answer,
    };
  });
}

function flagEmojiToIso(flag: string) {
  if (!flag) return null;
  // Flag emojis are two regional indicator symbols (U+1F1E6 = 'A', etc.)
  const codePoints = [...flag].map((c) => c.codePointAt(0) as number);
  if (codePoints.length < 2) return null;
  const A = 0x1f1e6;
  const Z = 0x1f1ff;
  if (codePoints[0] < A || codePoints[0] > Z || codePoints[1] < A || codePoints[1] > Z) return null;
  const a = String.fromCharCode(65 + (codePoints[0] - A));
  const b = String.fromCharCode(65 + (codePoints[1] - A));
  return (a + b).toLowerCase();
}

function buildFlagQs(data: any[]) {
  const allNames = data.map((c) => c.name);
  return data
    .filter((c) => c.flag) // keep only entries with a flag emoji
    .map((c) => {
      const distractors = pickDistractors(c.name, allNames);
      const { options, answer } = buildOptions(c.name, distractors);
      const iso = flagEmojiToIso(c.flag);
      return {
        q: `De quel pays est ce drapeau ?`,
        qHt: `Ki peyi ki gen drapo sa a ?`,
        flag: c.flag,
        flagIso: iso,
        options,
        answer,
      };
    });
}

/* ─── Static, hand-written question banks ───────────────────────────────────
 * These cover Haiti-specific knowledge and general science. Each item lists the
 * correct answer at index `answer`; `randomizeBank` then shuffles the option
 * order at load time so the right answer is never in a predictable position.
 * ────────────────────────────────────────────────────────────────────────── */

/** Shuffle the options of each static question and re-point `answer`. */
function randomizeBank(questions: any[]) {
  return questions.map((item) => {
    const correct = item.options[item.answer];
    const options = shuffleArr(item.options);
    return { ...item, options, answer: options.indexOf(correct) };
  });
}

